<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>Conway's Game of Life</title>
  <style>
    :root {
      color-scheme: dark;
      --bg: #090b17;
      --panel: #15182b;
      --text: #f3f5ff;
      --muted: #a8afcf;
      --cyan: #5ef2e7;
      --pink: #ff67b5;
      --purple: #9b7bff;
    }

    * {
      box-sizing: border-box;
    }

    body {
      min-height: 100vh;
      margin: 0;
      padding: 28px 16px;
      display: grid;
      place-items: center;
      overflow-x: auto;
      color: var(--text);
      font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
      background:
        radial-gradient(circle at 20% 15%, #252052 0, transparent 32%),
        radial-gradient(circle at 80% 80%, #123f4b 0, transparent 28%),
        var(--bg);
    }

    main {
      width: max-content;
      min-width: 400px;
      text-align: center;
    }

    h1 {
      margin: 0;
      font-size: clamp(2rem, 5vw, 3.3rem);
      letter-spacing: -0.05em;
      text-shadow: 0 0 28px rgba(94, 242, 231, 0.25);
    }

    .subtitle {
      margin: 6px 0 18px;
      color: var(--muted);
    }

    .board-shell {
      position: relative;
      width: 616px;
      margin: auto;
      padding: 8px;
      border: 1px solid rgba(155, 123, 255, 0.36);
      border-radius: 22px;
      background: rgba(18, 21, 40, 0.86);
      box-shadow:
        0 24px 70px rgba(0, 0, 0, 0.48),
        0 0 40px rgba(94, 242, 231, 0.08);
    }

    #life {
      display: block;
      width: 600px;
      height: 600px;
      border-radius: 15px;
      background: #0b0e1b;
      cursor: crosshair;
      touch-action: none;
      user-select: none;
    }

    .controls {
      width: 616px;
      margin: 16px auto 0;
      padding: 12px;
      display: flex;
      flex-wrap: wrap;
      justify-content: center;
      gap: 10px;
      border: 1px solid rgba(255, 255, 255, 0.08);
      border-radius: 18px;
      background: rgba(21, 24, 43, 0.9);
      box-shadow: 0 12px 35px rgba(0, 0, 0, 0.28);
    }

    button {
      min-width: 112px;
      padding: 11px 16px;
      border: 1px solid rgba(255, 255, 255, 0.13);
      border-radius: 999px;
      color: var(--text);
      font: inherit;
      font-weight: 750;
      letter-spacing: 0.01em;
      background: linear-gradient(145deg, #292e52, #1a1e37);
      box-shadow: 0 5px 0 #0c0e1d;
      cursor: pointer;
      transition: transform 100ms ease, filter 120ms ease, box-shadow 100ms ease;
    }

    button:hover {
      filter: brightness(1.2);
      transform: translateY(-1px);
    }

    button:active {
      transform: translateY(3px);
      box-shadow: 0 2px 0 #0c0e1d;
    }

    button:focus-visible {
      outline: 3px solid var(--cyan);
      outline-offset: 3px;
    }

    #play {
      background: linear-gradient(145deg, #087d78, #14505e);
    }

    #play.running {
      background: linear-gradient(145deg, #b53478, #6f2f73);
    }

    #random {
      background: linear-gradient(145deg, #6b50cc, #3d397f);
    }

    #clear {
      background: linear-gradient(145deg, #743047, #492739);
    }

    .status {
      margin: 13px 0 0;
      color: var(--muted);
      font-size: 0.92rem;
    }

    .status strong {
      color: var(--cyan);
      font-variant-numeric: tabular-nums;
    }

    @media (max-width: 650px) {
      body {
        place-items: start center;
      }
    }
  </style>
</head>
<body>
  <main>
    <h1>Cosmic Life</h1>
    <p class="subtitle">Paint some cells and watch a tiny universe unfold.</p>

    <div class="board-shell">
      <canvas
        id="life"
        width="600"
        height="600"
        aria-label="Conway's Game of Life grid"
      ></canvas>
    </div>

    <div class="controls" aria-label="Simulation controls">
      <button id="step" type="button">⏭ Step</button>
      <button id="play" type="button" aria-pressed="false">▶ Play</button>
      <button id="random" type="button">✨ Random</button>
      <button id="clear" type="button">🧹 Clear</button>
    </div>

    <p class="status">
      Generation <strong id="generation">0</strong>
      &nbsp;·&nbsp;
      Living cells <strong id="population">0</strong>
    </p>
  </main>

  <script>
    (() => {
      "use strict";

      const W = 50;
      const H = 50;
      const CELL = 12;

      const canvas = document.getElementById("life");
      const ctx = canvas.getContext("2d");
      const stepButton = document.getElementById("step");
      const playButton = document.getElementById("play");
      const randomButton = document.getElementById("random");
      const clearButton = document.getElementById("clear");
      const generationLabel = document.getElementById("generation");
      const populationLabel = document.getElementById("population");

      let cells = new Uint8Array(W * H);
      let generation = 0;
      let timer = null;
      let painting = false;
      let paintValue = 1;
      let lastPainted = -1;

      function index(x, y) {
        return y * W + x;
      }

      function inBounds(x, y) {
        return Number.isInteger(x) &&
               Number.isInteger(y) &&
               x >= 0 && x < W &&
               y >= 0 && y < H;
      }

      function getCell(x, y) {
        return inBounds(x, y) ? cells[index(x, y)] : 0;
      }

      function population() {
        let count = 0;
        for (let i = 0; i < cells.length; i++) count += cells[i];
        return count;
      }

      function draw() {
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.fillStyle = "#0a0d19";
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        ctx.strokeStyle = "rgba(135, 151, 203, 0.105)";
        ctx.lineWidth = 1;
        ctx.beginPath();

        for (let x = 0; x <= W; x++) {
          const px = x * CELL + 0.5;
          ctx.moveTo(px, 0);
          ctx.lineTo(px, canvas.height);
        }

        for (let y = 0; y <= H; y++) {
          const py = y * CELL + 0.5;
          ctx.moveTo(0, py);
          ctx.lineTo(canvas.width, py);
        }

        ctx.stroke();

        ctx.save();
        ctx.shadowColor = "rgba(94, 242, 231, 0.8)";
        ctx.shadowBlur = 7;

        for (let y = 0; y < H; y++) {
          for (let x = 0; x < W; x++) {
            if (!cells[index(x, y)]) continue;

            const hue = 168 + ((x * 3 + y * 2 + generation) % 38);
            ctx.fillStyle = `hsl(${hue} 88% 67%)`;
            ctx.fillRect(x * CELL + 2, y * CELL + 2, CELL - 3, CELL - 3);

            ctx.fillStyle = "rgba(255,255,255,0.3)";
            ctx.fillRect(x * CELL + 3, y * CELL + 3, CELL - 6, 2);
          }
        }

        ctx.restore();
        generationLabel.textContent = String(generation);
        populationLabel.textContent = String(population());
      }

      function setCell(x, y, value) {
        if (!inBounds(x, y)) return;
        cells[index(x, y)] = value ? 1 : 0;
        draw();
      }

      function stepSimulation() {
        const next = new Uint8Array(W * H);

        for (let y = 0; y < H; y++) {
          for (let x = 0; x < W; x++) {
            let neighbours = 0;

            for (let dy = -1; dy <= 1; dy++) {
              for (let dx = -1; dx <= 1; dx++) {
                if (dx === 0 && dy === 0) continue;
                neighbours += getCell(x + dx, y + dy);
              }
            }

            const alive = cells[index(x, y)] === 1;
            next[index(x, y)] =
              alive
                ? (neighbours === 2 || neighbours === 3 ? 1 : 0)
                : (neighbours === 3 ? 1 : 0);
          }
        }

        cells = next;
        generation++;
        draw();
      }

      function clearSimulation() {
        cells.fill(0);
        generation = 0;
        draw();
      }

      function randomize() {
        for (let i = 0; i < cells.length; i++) {
          cells[i] = Math.random() < 0.27 ? 1 : 0;
        }
        generation = 0;
        draw();
      }

      function setPlaying(shouldPlay) {
        if (shouldPlay && timer === null) {
          timer = setInterval(stepSimulation, 110);
          playButton.textContent = "⏸ Pause";
          playButton.classList.add("running");
          playButton.setAttribute("aria-pressed", "true");
        } else if (!shouldPlay && timer !== null) {
          clearInterval(timer);
          timer = null;
          playButton.textContent = "▶ Play";
          playButton.classList.remove("running");
          playButton.setAttribute("aria-pressed", "false");
        }
      }

      function pointerCell(event) {
        const rect = canvas.getBoundingClientRect();
        const x = Math.floor((event.clientX - rect.left) * W / rect.width);
        const y = Math.floor((event.clientY - rect.top) * H / rect.height);
        return { x, y };
      }

      function paintAt(event) {
        const { x, y } = pointerCell(event);
        if (!inBounds(x, y)) return;

        const i = index(x, y);
        if (i === lastPainted) return;

        cells[i] = paintValue;
        lastPainted = i;
        draw();
      }

      canvas.addEventListener("pointerdown", event => {
        event.preventDefault();
        const { x, y } = pointerCell(event);
        if (!inBounds(x, y)) return;

        painting = true;
        lastPainted = -1;
        paintValue = getCell(x, y) ? 0 : 1;
        canvas.setPointerCapture(event.pointerId);
        paintAt(event);
      });

      canvas.addEventListener("pointermove", event => {
        if (painting) paintAt(event);
      });

      function stopPainting(event) {
        painting = false;
        lastPainted = -1;
        if (canvas.hasPointerCapture(event.pointerId)) {
          canvas.releasePointerCapture(event.pointerId);
        }
      }

      canvas.addEventListener("pointerup", stopPainting);
      canvas.addEventListener("pointercancel", stopPainting);

      stepButton.addEventListener("click", stepSimulation);
      playButton.addEventListener("click", () => setPlaying(timer === null));
      randomButton.addEventListener("click", randomize);
      clearButton.addEventListener("click", clearSimulation);

      window.life = {
        w: W,
        h: H,
        get: getCell,
        set: setCell,
        step: stepSimulation,
        clear: clearSimulation
      };

      draw();
    })();
  </script>
</body>
</html>
